export function initialize(dotNetRef, timeoutMs) {
    const state = {
        isIdle: false,
        timerId: null,
        dotNetRef,
        timeoutMs,
        handlers: {}
    };

    function resetTimer() {
        clearTimeout(state.timerId);
        if (state.isIdle) {
            state.isIdle = false;
            state.dotNetRef.invokeMethodAsync('OnUserActive');
        }
        state.timerId = setTimeout(() => {
            state.isIdle = true;
            state.dotNetRef.invokeMethodAsync('OnUserIdle');
        }, state.timeoutMs);
    }

    const events = ['mousemove', 'keydown', 'click', 'scroll'];
    events.forEach(evt => {
        const handler = () => resetTimer();
        state.handlers[evt] = handler;
        document.addEventListener(evt, handler, { passive: true });
    });

    // Start the initial timer
    state.timerId = setTimeout(() => {
        state.isIdle = true;
        state.dotNetRef.invokeMethodAsync('OnUserIdle');
    }, state.timeoutMs);

    return state;
}

export function dispose(state) {
    clearTimeout(state.timerId);
    const events = ['mousemove', 'keydown', 'click', 'scroll'];
    events.forEach(evt => {
        document.removeEventListener(evt, state.handlers[evt]);
    });
}

